mapper.select:
select * from setmeal


        and name like concat('%',#{name},'%')


        and category_id = #{categoryId}


        and status = #{status}

select setmeal.*,category.name as categoryName from setmeal
         left join category on setmeal.category_id = category.id

    and setmeal.name=concat('%',#{name},'%')
    and setmeal.category_id=#{categoryId}
    and setmeal.status=#{status}

order by setmeal.update_time desc
